    }, [studies, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('investigation', currentProjectId), investigation);
    }, [investigation, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('contacts', currentProjectId), contacts);
    }, [contacts, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage('globalAppData_testSetups', testSetups);
    }, [testSetups]);

    useEffect(() => {
        saveToLocalStorage(projectKey('publications', currentProjectId), publications);
    }, [publications, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('selectedTestSetupId', currentProjectId), selectedTestSetupId);
    }, [selectedTestSetupId, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('studyVariables', currentProjectId), studyVariables);
    }, [studyVariables, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('measurementProtocols', currentProjectId), measurementProtocols);
    }, [measurementProtocols, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('processingProtocols', currentProjectId), processingProtocols);
    }, [processingProtocols, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('experimentType', currentProjectId), experimentType);
    }, [experimentType, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('studyToMeasurementProtocolSelection', currentProjectId), studyToMeasurementProtocolSelection);
    }, [studyToMeasurementProtocolSelection, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('studyToProcessingProtocolSelection', currentProjectId), studyToProcessingProtocolSelection);
    }, [studyToProcessingProtocolSelection, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('studyToStudyVariableMapping', currentProjectId), studyToStudyVariableMapping);
    }, [studyToStudyVariableMapping, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('sensorToMeasurementProtocolMapping', currentProjectId), sensorToMeasurementProtocolMapping);
    }, [sensorToMeasurementProtocolMapping, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('studyToSensorMeasurementMapping', currentProjectId), studyToSensorMeasurementMapping);
    }, [studyToSensorMeasurementMapping, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('sensorToProcessingProtocolMapping', currentProjectId), sensorToProcessingProtocolMapping);
    }, [sensorToProcessingProtocolMapping, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('studyToSensorProcessingMapping', currentProjectId), studyToSensorProcessingMapping);
    }, [studyToSensorProcessingMapping, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage(projectKey('pageTabStates', currentProjectId), pageTabStates);
    }, [pageTabStates, currentProjectId]);

    useEffect(() => {
        saveToLocalStorage('globalAppData_projects', projects);
    }, [projects]);

    useEffect(() => {
        saveToLocalStorage('globalAppData_currentProjectId', currentProjectId);
    }, [currentProjectId]);

    // The dataset store handles persistence and lazy-loading; expose its helpers via context below.

    // Lazy-load example project dataset if needed
    useEffect(() => {
        let mounted = true;
        (async () => {
            try {
                // Check if we're in an example project
                if (!isExampleProject(currentProjectId)) return;
                
                // only act after dataset hydration attempt finished
                if (!initHydrated) return;

                // If an in-memory dataset already exists, no seeding needed
                if (selectedDataset) return;

                // Use the hook's seedExampleProject function
                await seedExampleProject(currentProjectId, {
                    setSelectedDataset,
                    setProjectDatasetName,
                    setProjectDatasetStats,
                    clearProjectDatasetName,
                    clearProjectDatasetStats
                });

                // Refresh in-memory app state from the newly written localStorage keys
                if (mounted) {
                    try { switchProject(currentProjectId); } catch (e) { /* ignore */ }
                }
            } catch (err) {
                console.error('[GlobalDataContext] seed example project error', err);
            }
        })();
        return () => { mounted = false; };
    }, [currentProjectId, initHydrated, selectedDataset]);

    // submission logic intentionally removed from context; use `useSubmitData` hook instead

    const dataMap = {
        studies: [studies, setStudies],
        contacts: [contacts, setContacts],
        testSetups: [testSetups, setTestSetups],
        investigation: [investigation, setInvestigation],
        publications: [publications, setPublications],
        selectedTestSetupId: [selectedTestSetupId, setSelectedTestSetupId],
        studyVariables: [studyVariables, setStudyVariables],
        measurementProtocols: [measurementProtocols, setMeasurementProtocols],
        processingProtocols: [processingProtocols, setProcessingProtocols],
        studyToMeasurementProtocolSelection: [studyToMeasurementProtocolSelection, setStudyToMeasurementProtocolSelection],
        studyToProcessingProtocolSelection: [studyToProcessingProtocolSelection, setStudyToProcessingProtocolSelection],
        studyToStudyVariableMapping: [studyToStudyVariableMapping, setStudyToStudyVariableMapping],
        sensorToMeasurementProtocolMapping: [sensorToMeasurementProtocolMapping, setSensorToMeasurementProtocolMapping],
        studyToSensorMeasurementMapping: [studyToSensorMeasurementMapping, setStudyToSensorMeasurementMapping],
        sensorToProcessingProtocolMapping: [sensorToProcessingProtocolMapping, setSensorToProcessingProtocolMapping],
        studyToSensorProcessingMapping: [studyToSensorProcessingMapping, setStudyToSensorProcessingMapping],
        screenWidth: [screenWidth, setScreenWidth],
        pageTabStates: [pageTabStates, setPageTabStates],
        experimentType: [experimentType, setExperimentType]
    };


    const value = {
        studies,
        setStudies,
        testSetups,
        setTestSetups,
        investigation,
        setInvestigation,
        contacts,
        setContacts,
        publications,
        setPublications,
        selectedTestSetupId,
        setSelectedTestSetupId,
        studyVariables,
        setStudyVariables,
        measurementProtocols,
        setMeasurementProtocols,
        processingProtocols,
        setProcessingProtocols,
        studyToMeasurementProtocolSelection,
        setStudyToMeasurementProtocolSelection,
        studyToProcessingProtocolSelection,
        setStudyToProcessingProtocolSelection,
        studyToStudyVariableMapping,
        setStudyToStudyVariableMapping,
        sensorToMeasurementProtocolMapping,
        setSensorToMeasurementProtocolMapping,
        studyToSensorMeasurementMapping,
        setStudyToSensorMeasurementMapping,
        sensorToProcessingProtocolMapping,
        setSensorToProcessingProtocolMapping,
        studyToSensorProcessingMapping,
        setStudyToSensorProcessingMapping,
        screenWidth,
        setScreenWidth,
        experimentType,
        setExperimentType,
        pageTabStates,
        setPageTabStates,
        selectedDataset,
        setSelectedDataset,
        loadDatasetSubtree,
        explorerOpen,
        setExplorerOpen,
        openExplorer,
        closeExplorer,
        resolveExplorerSelection,
        initDatasetHydrated: initHydrated,
        dataMap
    };
    // add project helpers and list
    value.projects = projects;
    value.currentProjectId = currentProjectId;
    value.DEFAULT_PROJECT_ID = DEFAULT_PROJECT_ID;
    value.MULTI_RUN_EXAMPLE_PROJECT_ID = MULTI_RUN_EXAMPLE_PROJECT_ID;
    value.createProject = createProject;
    value.deleteProject = deleteProject;
    value.renameProject = renameProject;
    value.switchProject = switchProject;
    value.resetProject = resetProject;
    value.updateProjectExperimentType = updateProjectExperimentType;
    value.DEFAULT_PROJECT_ID = DEFAULT_PROJECT_ID;
    value.DEFAULT_PROJECT_NAME = DEFAULT_PROJECT_NAME;
    return (
        <GlobalDataContext.Provider value={value}>
            {children}
        </GlobalDataContext.Provider>
    );
};

// hooks/useCombinedRefs.js
import { useCallback } from 'react';

const useCombinedRefs = (...refs) => {
  return useCallback((node) => {
    refs.forEach(ref => {
      if (ref === null) return; // Ignore null refs

      // Handle function refs
      if (typeof ref === 'function') {
        ref(node);
      }
      // Handle ref objects ({ current: ... })
      else if (ref && typeof ref === 'object') {
        // Ensure it's a ref object and not just a plain object
        if ('current' in ref) {
          ref.current = node;
        }
      }
    });
  }, [...refs]); // Re-create if any of the input refs change
};

export default useCombinedRefs;

import { useState, useMemo, useEffect, useRef } from 'react';
import Fuse from 'fuse.js';

/**
 * useFuseSearch
 * A small reusable hook that encapsulates Fuse.js search over an array of items.
 * Returns { query, setQuery, results, setResults }.
 * Options: { threshold, limit, debounce }
 */
export default function useFuseSearch(items = [], keys = [], options = {}) {
  const { threshold = 0.3, limit = 10, debounce = 150 } = options;

  const [query, setQuery] = useState('');
  const [results, setResults] = useState(items);

  // Recreate Fuse instance when items/keys/threshold change
  const fuse = useMemo(() => {
    try {
      return new Fuse(items || [], { keys, threshold });
    } catch (e) {
      // If Fuse can't be created (bad keys), fall back gracefully
      // eslint-disable-next-line no-console
      console.warn('useFuseSearch: failed to create Fuse instance', e);
      return null;
    }
  }, [items, keys, threshold]);

  const timerRef = useRef(null);

  useEffect(() => {
    // Clear any outstanding timer
    if (timerRef.current) {
      clearTimeout(timerRef.current);
    }

    if (!query) {
      // No query => return full list (debounced to avoid too many renders)
      timerRef.current = setTimeout(() => setResults(items), debounce);
      return () => clearTimeout(timerRef.current);
    }

    // Debounced search
    timerRef.current = setTimeout(() => {
      if (!fuse) {
        setResults(items);
        return;
      }
      const found = fuse.search(query, { limit }).map(r => r.item);
      setResults(found);
    }, debounce);

    return () => clearTimeout(timerRef.current);
  }, [query, fuse, items, debounce, limit]);

  // Keep results in sync if items change and there's no query
  useEffect(() => {
    if (!query) setResults(items);
  }, [items, query]);

  return { query, setQuery, results, setResults };
}

import React, { useEffect, useRef, useState } from 'react'; // Import useEffect

import "../styles.css";

// Hooks
import useCarouselNavigation from '../hooks/useCarouselNavigation';
import useDynamicHeightContainer from '../hooks/useDynamicHeightContainer';


import PageWrapper from '../layout/PageWrapper';
import { useLocation } from 'react-router-dom';

import { slides } from "../components/Slides/slides";
import SlideReloadOverlay from '../components/Slides/SlideReloadOverlay';
import { cn } from '../utils/utils';
import Heading1 from '../components/Typography/Heading1';
// ProjectSelector removed in favor of the single 'Change Project' button in the header
import { useGlobalDataContext } from '../contexts/GlobalDataContext';
import useSubmitData from '../hooks/useSubmitData';
import LoadingOverlay from '../components/ui/LoadingOverlay';
import TooltipButton from '../components/Widgets/TooltipButton';
import IconToolTipButton from '../components/Widgets/IconTooltipButton';
import { Layers, ChevronLeft, ChevronRight } from 'lucide-react';
import InAppExplorer from '../components/Widgets/InAppExplorer';
import ProjectSessionsModal from '../components/Widgets/ProjectSessionsModal';
import Heading3 from '../components/Typography/Heading3';

export const IsaQuestionnaire = () => {
  const totalPages = slides.length;

  const {
    currentPage,
    handleForward,
    handlePrevious,
    goToPage,
    isLastPage,
    translateXValue,
  } = useCarouselNavigation(totalPages);

  const {
    containerHeight,
    childRefs,
    handleChildHeightChange,
  } = useDynamicHeightContainer(currentPage, 400);

  const { setScreenWidth, pageTabStates, explorerOpen, resolveExplorerSelection, currentProjectId, projects, selectedTestSetupId, testSetups } = useGlobalDataContext();
  const { submitData, isSubmitting, message, error, cancel, retry, clearError } = useSubmitData();

  // Overlay state management - all overlays follow the same conditional rendering pattern
  const [showSessionsModal, setShowSessionsModal] = useState(false);
  const [isRemountingSlides, setIsRemountingSlides] = useState(false);
  const [slidesKey, setSlidesKey] = useState(() => currentProjectId ? `slides-${currentProjectId}-${Date.now()}` : 'slides-none');
  const hasInitializedProjectRef = useRef(false);
  const overlayTimeoutRef = useRef(null);
  const keyUpdateTimeoutRef = useRef(null);
  const MIN_OVERLAY_DURATION = 700;
  
  // Handler: Close project sessions modal
  const handleSessionsModalClose = () => {
    setShowSessionsModal(false);
  };
  
  // Handler: Close explorer (cancel = resolve with null)
  const handleExplorerClose = () => {
    resolveExplorerSelection(null);
  };

  // Handler: Confirm explorer selection
  const handleExplorerSelect = (files) => {
    resolveExplorerSelection(files);
  };

  // Always show the sessions modal when navigating to this route so the user can pick a project.
  // This makes the selection explicit on every visit (reload or client-side navigation).
  const location = useLocation();
  useEffect(() => {
    setShowSessionsModal(true);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [location.pathname]);

  // Set screen width based on persisted tab state for the active page and slide index.
  // Slides 0-6 (IntroductionSlide through OperatingConditionsSlide): tab-aware width
  //   - simple-view: max-w-5xl
  //   - grid-view: max-w-[100rem]
  // Slides 7+ (StudyVariableSlide onwards): always max-w-[100rem] for both simple and grid views
  useEffect(() => {
    const FIRST_WIDE_SLIDE_INDEX = 7; // StudyVariableSlide is at index 7

    if (currentPage >= FIRST_WIDE_SLIDE_INDEX) {
      // Always wide for slides from StudyVariableSlide onwards
      setScreenWidth('max-w-[100rem]');
    } else {
      // Tab-aware width for earlier slides (Introduction through OperatingConditionsSlide)
      const activeTab = pageTabStates?.[currentPage];
      if (activeTab === 'grid-view') {
        setScreenWidth('max-w-[100rem]');
      } else {
        setScreenWidth('max-w-5xl');
      }
    }
    
    // Reset to default width when component unmounts
    return () => {
      setScreenWidth('max-w-5xl');
    };
  }, [currentPage, pageTabStates, setScreenWidth]);

  useEffect(() => {
    if (!currentProjectId) {
      return;
    }

    if (!hasInitializedProjectRef.current) {
      hasInitializedProjectRef.current = true;
      return;
    }

    childRefs.current = [];
    setIsRemountingSlides(true);

    if (keyUpdateTimeoutRef.current) {
      clearTimeout(keyUpdateTimeoutRef.current);
    }
    if (overlayTimeoutRef.current) {
      clearTimeout(overlayTimeoutRef.current);
    }

    keyUpdateTimeoutRef.current = setTimeout(() => {
      setSlidesKey(`slides-${currentProjectId}-${Date.now()}`);
    }, 0);

    overlayTimeoutRef.current = setTimeout(() => {
      setIsRemountingSlides(false);
    }, MIN_OVERLAY_DURATION);

    return () => {
      if (keyUpdateTimeoutRef.current) {
        clearTimeout(keyUpdateTimeoutRef.current);
      }
      if (overlayTimeoutRef.current) {
        clearTimeout(overlayTimeoutRef.current);
      }
    };
  }, [currentProjectId, childRefs]);

  const handleSubmit = () => {
    // In a real application, you'd collect data from all forms here
    submitData().catch(() => {
      // errors are displayed in overlay message; no additional alert needed
    });
  };

  return (
    <PageWrapper>
      {/* All overlays follow consistent conditional rendering pattern with explicit handlers */}
      {isSubmitting && <LoadingOverlay message={message} onCancel={cancel} />}
      {error && <LoadingOverlay message={error.message || 'Submission failed'} isError onRetry={retry} onCancel={clearError} />}
      {showSessionsModal && <ProjectSessionsModal onClose={handleSessionsModalClose} />}
      {explorerOpen && <InAppExplorer onClose={handleExplorerClose} onSelect={handleExplorerSelect} />}

      <div className="relative">

        <div className="absolute top-0 right-0 z-50 flex items-center gap-2">
          {!showSessionsModal && (
            <>
              <div className="flex flex-col items-end max-w-[220px] mr-2">
                <div className="text-xs text-gray-500 truncate whitespace-nowrap">
                  {testSetups?.find(s => s.id === selectedTestSetupId)?.name || 'No test setup selected'}
                </div>
                <Heading3 className="text-sm text-gray-600 font-medium truncate whitespace-nowrap">
                  {projects.find(p => p.id === currentProjectId)?.name || 'No project selected'}
                </Heading3>
              </div>
              <IconToolTipButton
                icon={Layers}
                tooltipText="Open project/session chooser"
                onClick={() => setShowSessionsModal(true)}
                className=""
                aria-label="Change Project"
              />
            </>
          )}
        </div>

        <Heading1> ISA Questionnaire Form </Heading1>
      </div>

      <div className="flex justify-center items-center mb-1 gap-4">
        <TooltipButton
          onClick={handlePrevious}
          tooltipText={currentPage > 0 ? "Previous slide" : undefined}
          disabled={isRemountingSlides || currentPage === 0}
          className={cn(
            "p-2 rounded-full transition-colors duration-200",
            currentPage === 0
              ? "invisible"
              : "bg-blue-100 hover:bg-blue-200 text-blue-700"
          )}
        >
          <ChevronLeft className="h-5 w-5" />
        </TooltipButton>

        <div className="flex">
          {slides.map((slide, index) => (
            <TooltipButton
              key={index}
              tooltipText={`${slide.displayName}`}
              onClick={() => goToPage(index)}
              disabled={isRemountingSlides}
              className={cn(
                "h-2 p-1.5 w-12 mx-1 rounded-full transition-colors duration-300 cursor-pointer disabled:cursor-not-allowed disabled:opacity-60",
                index === currentPage
                  ? 'bg-blue-500'
                  : index < currentPage
                    ? 'bg-green-400'
                    : 'bg-gray-300'
              )}
            />
          ))}
        </div>

        <TooltipButton
          onClick={handleForward}
          tooltipText={!isLastPage(currentPage) ? "Next slide" : undefined}
          disabled={isRemountingSlides || isLastPage(currentPage)}
          className={cn(
            "p-2 rounded-full transition-colors duration-200",
            isLastPage(currentPage)
              ? "invisible"
              : "bg-blue-100 hover:bg-blue-200 text-blue-700"
          )}
        >
          <ChevronRight className="h-5 w-5" />
        </TooltipButton>
      </div>

      <div className="space-y-6">
        {/* Main content - mark as inert when any overlay is visible */}
        <div 
          aria-hidden={showSessionsModal || explorerOpen} 
          className={showSessionsModal || explorerOpen ? 'pointer-events-none select-none opacity-60' : ''}
        >
          <div
            className="relative overflow-hidden transition-all duration-300 ease-in-out"
            aria-busy={isRemountingSlides}
          >
            <div
              key={slidesKey}
              aria-hidden={isRemountingSlides}
              className={cn(
                "flex transition-transform duration-500 ease-in-out",
                isRemountingSlides ? 'pointer-events-none' : ''
              )}
              style={{ transform: `translateX(${translateXValue}%)` }}
            >
              {slides.map((slide, index) => {
                const SlideComponent = slide;
                // Only fully render the current slide and its immediate neighbors
                const shouldRender = Math.abs(index - currentPage) <= 1;

                return (
                  <div key={index} className='w-full overflow-hidden flex-shrink-0'>
                    <div style={{ height: containerHeight, transition: 'height 0.35s' }}>
                      {shouldRender ? (
                        <SlideComponent
                          ref={el => (childRefs.current[index] = el)}
                          onHeightChange={handleChildHeightChange}
                          currentPage={currentPage}
                          pageIndex={index}
                        />
                      ) : (
                        // Lightweight placeholder keeps layout but avoids mounting heavy components
                        <div ref={el => (childRefs.current[index] = el)} style={{ width: '100%', height: '100%' }} />
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
            <SlideReloadOverlay isVisible={isRemountingSlides} animationMs={MIN_OVERLAY_DURATION - 100} />
          </div>
        </div>

        <div className="flex items-center justify-center space-x-4 mx-5">
          {/* Previous: always rendered but invisible/disabled on first page to reserve space */}
          <TooltipButton
            onClick={handlePrevious}
            tooltipText={currentPage > 0 ? "Go to previous page" : undefined}
            disabled={isRemountingSlides || currentPage === 0}
            aria-hidden={currentPage === 0}
            className={`text-center text-white font-semibold disabled:opacity-50 disabled:cursor-not-allowed ${currentPage === 0 ? 'invisible' : ''}`}
          >
            <span className='w-30'>&lt; Previous</span>
          </TooltipButton>

          <TooltipButton
            tooltipText="Submit the form"
            onClick={handleSubmit}
            className={cn(
              "py-2 text-white font-semibold rounded-lg transition-colors duration-200 shadow-lg",
              "bg-gradient-to-r from-blue-500 to-blue-600 hover:from-blue-600 hover:to-blue-700 focus:ring-4 focus:ring-blue-200 hover:shadow-xl"
            )}
          >
            <span className='w-md'>Convert to ISA-PHM</span>
          </TooltipButton>

          {/* Next: always rendered but invisible/disabled on last page to reserve space */}
          <TooltipButton
            onClick={handleForward}
            tooltipText={!isLastPage(currentPage) ? "Go to next page" : undefined}
            disabled={isRemountingSlides || isLastPage(currentPage)}
            aria-hidden={isLastPage(currentPage)}
            className={`text-white font-semibold disabled:opacity-50 disabled:cursor-not-allowed ${isLastPage(currentPage) ? 'invisible' : ''}`}
          >
            <span className='w-30'>{currentPage === 0 ? 'Start' : 'Next >'}</span>
          </TooltipButton>
        </div>
      </div>
    </PageWrapper>
  );
};

export default IsaQuestionnaire;
